mapper.select:
SELECT COUNT(*) > 0 FROM bpm_batch_exec_log
WHERE batch_date = #{batchDate}
  AND version_name = #{versionName}
  AND node_code = #{nodeCode}
  AND status = 'SUCCESS'

mapper.update:
UPDATE bpm_batch_exec_log
SET status = 'FAILED', error_step = #{errorStep},
    error_message = #{errorMessage}, end_time = #{endTime}
WHERE id = #{id}
